import os

# Shadow agent tool registry — write tools are replaced with no-op stubs
READ_ONLY_TOOLS = {"web_search", "get_document", "list_files", "read_database"}
WRITE_TOOLS = {"send_email", "write_database", "create_ticket", "post_message"}

def get_tool_for_agent(tool_name: str, is_shadow: bool):
    """Return the real tool in production mode; return a stub in shadow mode."""
    if not is_shadow:
        return REAL_TOOLS[tool_name]

    if tool_name in READ_ONLY_TOOLS:
        return REAL_TOOLS[tool_name]  # Safe to execute in shadow

    if tool_name in WRITE_TOOLS:
        return shadow_stub(tool_name)  # No-op stub

    raise ValueError(f"Unknown tool: {tool_name} — classify it before shadow use")


def shadow_stub(tool_name: str):
    """Returns a stub that logs the intended call but takes no real action."""
    async def stub(**kwargs):
        print(f"[SHADOW STUB] Would have called {tool_name} with {kwargs}")
        return {"status": "ok", "shadow_stub": True, "tool": tool_name}
    return stub
